// TestNovelDedupeHelpWires smoke-tests that the dedupe command resolves at
// runtime and renders --help without error.
func TestNovelDedupeHelpWires(t *testing.T) {
	cmd := RootCmd()
	cmd.SetArgs([]string{"dedupe", "--help"})
	cmd.SetOut(io.Discard)
	cmd.SetErr(io.Discard)
	if err := cmd.Execute(); err != nil {
		t.Fatalf("dedupe --help error = %v (novel command not wired correctly?)", err)
	}
}

func seedPerson(t *testing.T, s *store.Store, id string, fields map[string]any) {
	t.Helper()
	if fields == nil {
		fields = map[string]any{}
	}
	fields["id"] = id
	data, err := json.Marshal(fields)
	if err != nil {
		t.Fatalf("marshal person %s: %v", id, err)
	}
	if err := s.UpsertPeople(data); err != nil {
		t.Fatalf("upsert person %s: %v", id, err)
	}
}

func TestNovelDedupeBehavior(t *testing.T) {
	s := newTestStore(t)
	// Two people share a@x.com (case-insensitive), one has b@x.com.
	seedPerson(t, s, "1", map[string]any{"name": "Ann", "email": "a@x.com"})
	seedPerson(t, s, "2", map[string]any{"name": "Andy", "email": "A@X.com"})
	seedPerson(t, s, "3", map[string]any{"name": "Bob", "email": "b@x.com"})

	groups, err := runDedupe(context.Background(), s.DB(), "people", "email")
	if err != nil {
		t.Fatalf("runDedupe: %v", err)
	}
	if len(groups) != 1 {
		t.Fatalf("want 1 dup group, got %d: %+v", len(groups), groups)
	}
	g := groups[0]
	if g.Key != "a@x.com" {
		t.Errorf("group key = %q, want a@x.com", g.Key)
	}
	if g.Count != 2 || len(g.Members) != 2 {
		t.Errorf("group size = %d (members %d), want 2", g.Count, len(g.Members))
	}
	ids := map[string]bool{}
	for _, m := range g.Members {
		ids[m.ID] = true
	}
	if !ids["1"] || !ids["2"] {
		t.Errorf("members = %+v, want ids 1 and 2", g.Members)
	}

	// No duplicates on a unique key.
	byName, err := runDedupe(context.Background(), s.DB(), "people", "name")
	if err != nil {
		t.Fatalf("runDedupe name: %v", err)
	}
	if len(byName) != 0 {
		t.Errorf("dedupe by unique name = %d groups, want 0", len(byName))
	}
}
